const classifierItems = $input.all();
const originalEmailItems = $items('Kill Switch - Pass Email Items');

return classifierItems.map((item, index) => {
  let content =
    item.json.choices?.[0]?.message?.content ||
    item.json.message?.content ||
    item.json.content ||
    item.json.text ||
    '';

  content = String(content).trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json/i, '')
      .replace(/^```/i, '')
      .replace(/```$/i, '')
      .trim();
  }

  let parsed;

  try {
    parsed = JSON.parse(content);
  } catch (error) {
    parsed = {
      category: 'other',
      route: 'custom',
      confidence: 0,
      priority: 'P2',
      sentiment: 'neutral',
      reason: 'Classifier JSON parse failed'
    };
  }

  const original = originalEmailItems[index]?.json || {};

  return {
    json: {
      ...original,
      category: parsed.category || 'other',
      route: parsed.route || 'custom',
      confidence: parsed.confidence ?? 0,
      priority: parsed.priority || 'P2',
      sentiment: parsed.sentiment || 'neutral',
      reason: parsed.reason || ''
    }
  };
});

