const settings = $input.all();
const killSwitchValue = settings[0]?.json?.Value;

if (killSwitchValue !== 'ON') {
  return [];
}

return $items('Dedupe - Restore Email Items');

const passedItems = $input.all();
const originalEmailItems = $items('04 Prepare Email Fields');

return passedItems.map((item, index) => {
  const pairedItem = Array.isArray(item.pairedItem)
    ? item.pairedItem[0]
    : item.pairedItem;

  const originalIndex = pairedItem?.item ?? index;
  const original = originalEmailItems[originalIndex]?.json || {};

  return {
    json: {
      ...original
    }
  };
});

const drafterItems = $input.all();
const originalDraftItems = $items('07 Switch - Route');

return drafterItems.map((item, index) => {
  const original = originalDraftItems[index]?.json || {};

  const draftBody =
    item.json.choices?.[0]?.message?.content ||
    item.json.message?.content ||
    item.json.content ||
    item.json.text ||
    '';

  return {
    json: {
      ...original,
      draft_body: String(draftBody).trim(),
      drafter_raw_response: item.json
    }
  };
});

const createDraftItems = $input.all();
const originalDraftItems = $items('Merge Drafter Response');

return createDraftItems.map((item, index) => {
  const original = originalDraftItems[index]?.json || {};
